export const getRandomMarketValuePlayer = (usedIds: string[] = [], baseValue?: number, currentStreak: number = 0): Player => {
  let available = marketValuePlayers.filter(p => !usedIds.includes(p.id));

  if (available.length === 0) {
    available = marketValuePlayers; // Reset if all are used
  }

  if (baseValue !== undefined) {
    let gap = 50; 
    if (currentStreak > 5) gap = 40;
    if (currentStreak > 10) gap = 30;
    if (currentStreak > 15) gap = 20;
    if (currentStreak > 20) gap = 15;

    const min = Math.max(0, baseValue - gap);
    const max = baseValue + gap;

    const closePlayers = available.filter(p => p.value >= min && p.value <= max);
    if (closePlayers.length > 0) {
      return closePlayers[Math.floor(Math.random() * closePlayers.length)];
    }
  }

  return available[Math.floor(Math.random() * available.length)];
};
